{
  "host": "Cloudflare",
  "source": "Workflow.LogEntry",
  "dataSource": {
    "name": "LogEntry",
    "category": "Workflow",
    "vendor": "Cloudflare"
  },
  "event": {
    "severity": "FINER",
    "message": "Discovered username {{local_var.discoveredUsername}} from other alert data (eg: loggedInUser or process.username)",
    "record": {
      "type": "Cloudflare.Workflow.LogEntry",
      "version": 1
    },
    "userInfo": {
      "username": "{{local_var.discoveredUsername}}"
    },
    "workflow": {
      "metadata": {{local_var.workflowMetadata}},
      "messages": {{local_var.workflowMessages}},
      "state": {{local_var.workflowState}}
    }
  }
}

{
  "host": "Cloudflare",
  "source": "Workflow.LogEntry",
  "dataSource": {
    "name": "LogEntry",
    "category": "Workflow",
    "vendor": "Cloudflare"
  },
  "event": {
    "severity": "INFO",
    "message": "Unable to discover a username or email address information from the alert.",
    "record": {
      "type": "Cloudflare.Workflow.LogEntry",
      "version": 1
    },
    "alert": {{singularity-response-trigger.data}},
    "workflow": {
      "metadata": {{local_var.workflowMetadata}},
      "messages": {{Function.APPEND(local_var.workflowMessages, "unable to locate username or email address information in the alert")}},
      "state": "ABORTED"
    }
  }
}

